example.code:
// 定义自定义 Attribute
[AttributeUsage(AttributeTargets.Class)]
public sealed class ServiceAttribute : MarkerAttribute
{
    public Type ServiceType { get; }
    public ServiceAttribute(Type serviceType) => ServiceType = serviceType;
}

// 使用
[Service(typeof(IMyService))]
public sealed class MyServiceImpl : IMyService { }

// 框架扫描并处理
MarkerScanner<ServiceAttribute>.Scan(assemblies, registry);

public sealed class MyMarkerBootstrapper : MarkerBootstrapper<MyAttribute, MyRegistry>
{
    public MyMarkerBootstrapper() : base(MyRegistry.Instance) { }
}

// 框架初始化时调用
MarkerSystem.ScanAll();

// 或者扫描特定包
MarkerSystem.ScanAll(new[] { typeof(MyAttribute).Assembly });
